import React from "react";

import styles from "./QuickInfoCard.module.css";

export interface QuickInfoItem {
  icon?: React.ReactNode;
  label: string;
  value: string | number;
  valueColor?: "default" | "success" | "warning" | "danger";
  mono?: boolean;
}

export interface StorageProgress {
  used: number;
  limit: number;
}

export interface QuickInfoCardProps extends React.HTMLAttributes<HTMLDivElement> {
  items: QuickInfoItem[];
  storageProgress?: StorageProgress;
  showCornerBrackets?: boolean;
}

function formatFileSize(bytes: number) {
  if (bytes === 0) {
    return "0 Bytes";
  }

  const base = 1024;
  const sizes = ["Bytes", "KB", "MB", "GB"];
  const unitIndex = Math.floor(Math.log(bytes) / Math.log(base));
  return `${parseFloat((bytes / Math.pow(base, unitIndex)).toFixed(2))} ${
    sizes[unitIndex]
  }`;
}

export function QuickInfoCard({
  items,
  storageProgress,
  className = "",
  showCornerBrackets = true,
  ...props
}: QuickInfoCardProps) {
  const storageRatio = storageProgress
    ? storageProgress.used / Math.max(storageProgress.limit, 1)
    : 0;
  const storageToneClass =
    storageRatio > 0.9
      ? styles.storageDanger
      : storageRatio > 0.7
        ? styles.storageWarning
        : "";

  const getValueToneClass = (color?: QuickInfoItem["valueColor"]) => {
    switch (color) {
      case "success":
        return styles.valueSuccess;
      case "warning":
        return styles.valueWarning;
      case "danger":
        return styles.valueDanger;
      default:
        return "";
    }
  };

  return (
    <div
      className={`${styles.card} ${showCornerBrackets ? styles.cardWithBrackets : ""} ${className}`.trim()}
      {...props}
    >
      {items.map((item, index) => (
        <div key={`${item.label}-${index}`} className={styles.item}>
          {item.icon ? <div className={styles.icon}>{item.icon}</div> : null}
          <div className={styles.info}>
            <span className={styles.label}>{item.label}</span>
            <span
              className={`${styles.value} ${item.mono ? styles.valueMono : ""} ${getValueToneClass(item.valueColor)}`.trim()}
            >
              {item.value}
            </span>
          </div>
        </div>
      ))}
      {storageProgress ? (
        <div className={styles.storageProgress}>
          <div className={styles.storageProgressLabel}>
            <span>Storage</span>
            <span className={styles.storageProgressValue}>
              {formatFileSize(storageProgress.used)} /{" "}
              {formatFileSize(storageProgress.limit)}
            </span>
          </div>
          <div className={styles.storageProgressBar}>
            <div
              className={`${styles.storageProgressFill} ${storageToneClass}`.trim()}
              style={
                {
                  "--storage-progress-width": `${Math.min(storageRatio * 100, 100)}%`,
                } as React.CSSProperties
              }
            />
          </div>
        </div>
      ) : null}
    </div>
  );
}

export default QuickInfoCard;

.card {
  display: flex;
  gap: 1.5rem;
  padding: 1rem 1.5rem;
  margin: 0.75rem;
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  flex-wrap: wrap;
  position: relative;
  overflow: visible;
}

.cardWithBrackets::before {
  content: "";
  position: absolute;
  top: -0.5rem;
  left: -0.5rem;
  width: 0.5rem;
  height: 0.5rem;
  border-top: 1px solid var(--border-color);
  border-left: 1px solid var(--border-color);
}

.cardWithBrackets::after {
  content: "";
  position: absolute;
  bottom: -0.5rem;
  right: -0.5rem;
  width: 0.5rem;
  height: 0.5rem;
  border-bottom: 1px solid var(--border-color);
  border-right: 1px solid var(--border-color);
}

.item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  flex: 1;
  min-width: 150px;
}

.icon {
  display: grid;
  place-items: center;
  flex-shrink: 0;
  color: var(--accent-primary);
}

.icon :global(svg) {
  width: 1.25rem;
  height: 1.25rem;
}

.info {
  display: flex;
  flex-direction: column;
  gap: 0.125rem;
  flex: 1;
}

.label {
  color: var(--text-secondary);
  font-size: 0.6875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.value {
  color: var(--text-primary);
  font-size: 1rem;
  font-weight: 600;
}

.valueMono {
  font-family: var(--font-mono);
}

.valueSuccess {
  color: var(--color-success, #10b981);
}

.valueWarning {
  color: var(--color-warning, #f59e0b);
}

.valueDanger {
  color: var(--color-error, #ef4444);
}

.storageProgress {
  flex: 1;
  min-width: 200px;
  display: flex;
  flex-direction: column;
  gap: 0.375rem;
}

.storageProgressLabel {
  display: flex;
  justify-content: space-between;
  color: var(--text-secondary);
  font-size: 0.6875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.storageProgressValue {
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-weight: 600;
}

.storageProgressBar {
  height: 8px;
  background: color-mix(in srgb, var(--bg-primary) 82%, transparent);
  border-radius: 4px;
  overflow: hidden;
  border: 1px solid var(--border-color);
}

.storageProgressFill {
  height: 100%;
  width: var(--storage-progress-width, 0%);
  background: var(--accent-primary);
  border-radius: 3px;
  transition: width 220ms ease;
}

.storageWarning {
  background: var(--color-warning, #f59e0b);
}

.storageDanger {
  background: var(--color-error, #ef4444);
}
